import React, { type FC } from "react";
import type {IFileUploader} from "@lmb/kitsconcerto-types";
import MainUploader from "./MainUploader";
import {KitsContainer} from "../../../../";

const FilePicker: FC<IFileUploader> = (props) => {
    const { id, helperText, disabled, label, errors, hideError, invalid } = props;

    return (
        <KitsContainer
            id={id}
            className={"file-picker-component"}
            disabled={disabled}
            label={label}
            hideError={hideError}
            errors={errors}
            invalid={invalid}
            helperText={helperText}
            isFloatedLabel={false}
        >
            <MainUploader name={id} {...props} />
        </KitsContainer>
    );
};

export default FilePicker;
